    // normalizações de Vitamina D
    .replace(/25O0HD/gi, "25OHD")   // corrige zero indevido
    .replace(/250HD/gi, "25OHD")    // corrige zero no lugar do O
   // normalização HbA1c (OCR variations)
    .replace(/HB1[\|I\-\s_]*AC/gi, "HB1AC")

// ── Siglas com lixo de OCR ─────────────────
    .replace(/\bDAGSRH\b/gi, "GSRH")
    .replace(/\bDOCREA\b/gi, "CRE");

return itens.map((item) => {
  const json = { ...item.json };

  for (const f of FIELDS) {
    if (json[f] !== undefined && json[f] !== null) {
      json[f] = fix(json[f]);
    }
  }

  return { json };
});
